		}
		can := filepath.Clean(exp)
		if _, ok := byCanon[can]; !ok {
			byCanon[can] = p
		}
	}
	out := make([]string, 0, len(byCanon))
	for _, orig := range byCanon {
		out = append(out, orig)
	}
	sort.Strings(out)
	return out
}

