14	)
15	
16	// RegisterSkills registers the skills command group.
17	func RegisterSkills(rootCmd *cobra.Command) {
18		skillsCmd := &cobra.Command{
19			Use:   "skills",
20			Short: "Manage Port AI skills: hooks and local skill sync",
21			Long: `Manage Port AI skills: hooks and local skill sync.
22	
23	Use 'port skills init' to install session-start hooks into your AI tools
24	(Cursor, Claude Code, Gemini CLI, OpenAI Codex, Windsurf, GitHub Copilot).
25	Once installed, every new AI session will automatically sync your selected skills
26	from Port.`,
27		}
28	
29		skillsCmd.AddCommand(registerSkillsInit())
30		skillsCmd.AddCommand(registerSkillsAdd())
31		skillsCmd.AddCommand(registerSkillsRemove())
32		skillsCmd.AddCommand(registerSkillsSync())
33		skillsCmd.AddCommand(registerSkillsList())
34		skillsCmd.AddCommand(registerSkillsClear())
35		skillsCmd.AddCommand(registerSkillsStatus())
36	
37		rootCmd.AddCommand(skillsCmd)
38	}
39	
40	func registerSkillsInit() *cobra.Command {
41		return &cobra.Command{
42			Use:   "init",
43			Short: "Install AI session-start hooks and sync skills from Port",
44			Long: `Install AI session-start hooks for Cursor, Claude Code, Gemini CLI, OpenAI Codex, Windsurf, and GitHub Copilot.
45	
46	On every new AI session the hook will run 'port skills sync',
47	keeping your local skills in sync with the Port registry. Hooks are installed
48	globally in your home directory for most tools. GitHub Copilot is different:
49	hooks and synced skills are installed only under <repo>/.github (run init from
50	the repository root).
51	Skills are written to the correct location based on each skill's 'location'
52	property in Port ("global" → AI tool directories, "project" → tool directory
53	inside each registered project directory). For Copilot, both global and
54	project skills from Port are written under <repo>/.github/skills/port/.`,
55			RunE: func(cmd *cobra.Command, args []string) error {
56				ctx := cmd.Context()
57				flags := GetGlobalFlags(ctx)
58				configManager := config.NewConfigManager(flags.ConfigFile)
59	
60				targets, err := promptTargetSelection(configManager)
61				if err != nil {
62					return err
63				}
64	
65				mod, configManager, err := newSkillsModuleWithFlags(ctx, flags)
66				if err != nil {
67					return err
68				}
69	
70				initResult, err := mod.Init(ctx, skills.InitOptions{
71					Targets: targets,
72				})
73				if err != nil {
74					return fmt.Errorf("failed to install hooks: %w", err)
75				}
76	
77				for _, t := range initResult.InstalledTargets {
78					lipgloss.Printf("%s Hook installed in %s\n", styles.CheckMark, styles.Bold.Render(t))
79				}
80	
81				loadOpts, err := buildLoadSkillsOpts(ctx, mod, true)
82				if err != nil {
83					return err
84				}
85	
86				if clearResult, err := mod.ClearSkills(); err != nil {
87					return fmt.Errorf("failed to clear existing skills: %w", err)
88				} else {
89					for _, t := range clearResult.DeletedTargets {
90						lipgloss.Printf("%s Cleared existing skills from %s\n", styles.CheckMark, styles.Bold.Render(t))
91					}
92				}
93	
94				result, err := mod.LoadSkills(ctx, loadOpts)
95				if err != nil {
96					return fmt.Errorf("failed to sync skills: %w", err)
97				}
98				printLoadResult(result)
99				return nil
100			},
101		}
102	}
103	
104	func registerSkillsAdd() *cobra.Command {
105		var (
106			groups    []string
107			skillsIDs []string
108			tools     []string
109		)
110	
111		cmd := &cobra.Command{
112			Use:   "add",
113			Short: "Add skills or AI tools to your existing selection",
114			Long: `Add skill groups, individual skills, or AI tool targets to your saved
115	selection without re-selecting everything configured during 'port skills init'.
116	
117	When run without flags, an interactive prompt lists only groups, ungrouped
118	skills, and AI tools that are not already part of your configuration.
119	
120	After updating the selection, skills are synced to disk (same as 'port skills sync').`,
121			RunE: func(cmd *cobra.Command, args []string) error {
122				ctx := cmd.Context()
123				flags := GetGlobalFlags(ctx)
124	
125				mod, configManager, err := newSkillsModuleWithFlags(ctx, flags)
126				if err != nil {
127					return err
128				}
129	
130				skillsCfg, err := configManager.LoadSkillsConfig()
131				if err != nil {
132					skillsCfg = &config.SkillsConfig{}
133				}
134	
135				addOpts := skills.AddSkillsOptions{
136					Groups: groups,
137					Skills: skillsIDs,
138				}
139	
140				nonInteractive := cmd.Flags().Changed("group") || cmd.Flags().Changed("skill") || cmd.Flags().Changed("tool")
141				if !nonInteractive {
142					fetched, err := mod.FetchSkills(ctx)
143					if err != nil {
144						return fmt.Errorf("failed to fetch skills from Port: %w", err)
145					}
146	
147					availableGroups := skills.AvailableGroupsToAdd(skillsCfg, fetched)
148					if len(availableGroups) > 0 {
149						selected, err := promptAddGroupSelection(availableGroups)
150						if err != nil {
151							return err
152						}
153						addOpts.Groups = append(addOpts.Groups, selected...)
154					}
155	
156					availableSkills := skills.AvailableSkillsToAdd(skillsCfg, fetched)
157					if len(availableSkills) > 0 {
158						selected, err := promptAddSkillSelection(availableSkills)
159						if err != nil {
160							return err
161						}
162						addOpts.Skills = append(addOpts.Skills, selected...)
163					}
164	
165					unconfigured, err := unconfiguredHookTargets(configManager)
166					if err != nil {
167						return err
168					}
169					if len(unconfigured) > 0 {
170						configuredTools, err := configuredHookTargetNames(configManager)
171						if err != nil {
172							return err
173						}
174						targets, err := promptAddTargetSelection(unconfigured, configuredTools)
175						if err != nil {
176							return err
177						}
178						addOpts.Targets = targets
179					}
180	
181					if len(addOpts.Groups) == 0 && len(addOpts.Skills) == 0 && len(addOpts.Targets) == 0 {
182						lipgloss.Printf("%s Nothing new to add — your current selection already includes all optional skills and configured tools.\n", styles.QuestionMark)
183						return nil
184					}
185				} else if len(tools) > 0 {
186					resolved, err := resolveTargetsByName(tools)
187					if err != nil {
188						return err
189					}
190					addOpts.Targets = resolved
191				}
192	
193				if !skillsCfg.HasSelection() && len(addOpts.Targets) == 0 &&
194					len(addOpts.Groups) == 0 && len(addOpts.Skills) == 0 {
195					return fmt.Errorf("no skill selection configured — run 'port skills init' first")
196				}
197				if nonInteractive && len(addOpts.Groups) == 0 && len(addOpts.Skills) == 0 && len(addOpts.Targets) == 0 {
198					return fmt.Errorf("specify at least one of --group, --skill, or --tool")
